pub fn decode_interleaved<S: Sample>(jxl: &[u8], channels: u32) -> Option<(Vec<S>, u32, u32)> {
    let mut dec = Decoder::new(DecodeOptions::default())?;
    let (w, h, _, data) = dec.run_raw::<S>(jxl, channels).ok()?;
    Some((data, w, h))
}

